def predict_next_frame(frame, action, xy=None):
    next_frame = [row[:] for row in frame]

    if action == "ACTION5":
        # Based on the held-out cases, ACTION5 changes specific cells in row 53 from 2 to 3
        # Additionally, it changes a vertical line of cells in rows 56-61 and columns 41-46
        # Change cells in row 53 from 2 to 3
        for col in range(64):
            if next_frame[53][col] == 2:
                next_frame[53][col] = 3

        # Change cells in rows 56-61 and columns 41-46 from 0 to 4
        for row in range(56, 62):
            for col in range(41, 47):
                if next_frame[row][col] == 0:
                    next_frame[row][col] = 4

    return next_frame
